import jwt from 'jsonwebtoken';
import { User } from '../models/user.model';
import { authConfig } from '../config/auth';
import { JwtPayload } from '../types/auth.types';
import { AppError, ErrorCodes } from '../utils/errors';

export interface AuthenticatedRequest extends Request {
  user?: {
    id: string;
    username: string;
    role: string;
    propertyId?: string;
  };
}

export async function authMiddleware(
  req: AuthenticatedRequest,
  _res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const authHeader = req.headers.authorization;
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      throw new AppError(
        ErrorCodes.UNAUTHORIZED.statusCode,
        ErrorCodes.UNAUTHORIZED.code,
        'Authentication required'
      );
    }

    const token = authHeader.slice(7);
    let payload: JwtPayload;
    try {
      payload = jwt.verify(token, authConfig.secret, {
        algorithms: [authConfig.algorithm],
      }) as JwtPayload;
    } catch {
      throw new AppError(
        ErrorCodes.UNAUTHORIZED.statusCode,
        ErrorCodes.UNAUTHORIZED.code,
        'Invalid or expired token'
      );
    }

    const user = await User.findByPk(payload.userId);
    if (!user) {
      throw new AppError(
        ErrorCodes.UNAUTHORIZED.statusCode,
        ErrorCodes.UNAUTHORIZED.code,
        'User not found'
      );
    }

    if (user.status !== 'active' || user.deleted_at !== null) {
      throw new AppError(
        ErrorCodes.FORBIDDEN.statusCode,
        ErrorCodes.FORBIDDEN.code,
        'Account is not active'
      );
    }

    req.user = {
      id: user.id,
      username: user.username,
      role: user.role,
      propertyId: user.property_id || undefined,
    };

    next();
  } catch (err) {
    next(err);
  }
}
"}

