13	    propertyId?: string;
14	  };
15	}
16	
17	export async function authMiddleware(
18	  req: AuthenticatedRequest,
19	  _res: Response,
20	  next: NextFunction
21	): Promise<void> {
22	  try {
23	    const authHeader = req.headers.authorization;
24	    if (!authHeader || !authHeader.startsWith('Bearer ')) {
25	      throw new AppError(
26	        ErrorCodes.UNAUTHORIZED.statusCode,
27	        ErrorCodes.UNAUTHORIZED.code,
28	        'Authentication required'
29	      );
30	    }
31	
32	    const token = authHeader.slice(7);
33	    let payload: JwtPayload;
34	    try {
35	      payload = jwt.verify(token, authConfig.secret, {
36	        algorithms: [authConfig.algorithm],
37	      }) as JwtPayload;
38	    } catch {
39	      throw new AppError(
40	        ErrorCodes.UNAUTHORIZED.statusCode,
41	        ErrorCodes.UNAUTHORIZED.code,
42	        'Invalid or expired token'
43	      );
44	    }
45	
46	    const user = await User.findByPk(payload.userId);
47	    if (!user) {
48	      throw new AppError(
49	        ErrorCodes.UNAUTHORIZED.statusCode,
50	        ErrorCodes.UNAUTHORIZED.code,
51	        'User not found'
52	      );
53	    }
54	
55	    if (user.status !== 'active' || user.deleted_at !== null) {
56	      throw new AppError(
57	        ErrorCodes.FORBIDDEN.statusCode,
58	        ErrorCodes.FORBIDDEN.code,
59	        'Account is not active'
60	      );
61	    }
62	
63	    req.user = {
64	      id: user.id,
65	      username: user.username,
66	      role: user.role,
67	      propertyId: user.property_id || undefined,
68	    };
69	
70	    next();
71	  } catch (err) {
72	    next(err);
73	  }
74	}
