1	import express, { Request, Response, NextFunction } from 'express';
2	import helmet from 'helmet';
3	import compression from 'compression';
4	import swaggerUi from 'swagger-ui-express';
5	import path from 'path';
6	import { auditMiddleware } from './middleware/audit.middleware';
7	import { AppError } from './utils/errors';
8	import { traceStore } from './utils/logger';
9	import { createCategoryLogger } from './utils/logger';
10	import authRoutes from './routes/auth.routes';
11	import accountsRoutes from './routes/accounts.routes';
12	import usersRoutes from './routes/users.routes';
13	
14	const systemLogger = createCategoryLogger('system');
15	
16	const app = express();
17	
18	// Security and compression
19	app.use(helmet());
20	app.use(compression());
21	app.use(express.json());
22	app.use(express.urlencoded({ extended: true }));
23	
24	// Trace ID on every request
25	app.use(auditMiddleware);
26	
27	// Health check
28	app.get('/health', (_req: Request, res: Response) => {
29	  res.json({ status: 'ok', timestamp: new Date().toISOString() });
30	});
31	
32	// Swagger UI
33	const stubSpec = {
34	  openapi: '3.0.3',
35	  info: {
36	    title: 'Hospitality Operations Intelligence API',
37	    version: '1.0.0',
38	    description: 'Hospitality Operations Intelligence & Group Itinerary Platform',
39	  },
40	  servers: [{ url: 'http://localhost:3000', description: 'Local' }],
41	  paths: {
42	    '/health': {
43	      get: {
44	        tags: ['Health'],
45	        summary: 'Health check',
46	        responses: {
47	          '200': {
48	            description: 'OK',
49	            content: {
50	              'application/json': {
51	                schema: {
52	                  type: 'object',
53	                  properties: {
54	                    status: { type: 'string', example: 'ok' },
55	                    timestamp: { type: 'string', format: 'date-time' },
56	                  },
57	                },
58	              },
59	            },
60	          },
61	        },
62	      },
63	    },
64	  },
65	};
66	
67	app.use('/api/docs', swaggerUi.serve, swaggerUi.setup(stubSpec));
68	
69	// API routes
70	app.use('/auth', authRoutes);
71	app.use('/accounts', accountsRoutes);
72	app.use('/users', usersRoutes);
73	
74	// Static file serving for exports
75	app.use('/exports', express.static(path.resolve('exports')));
76	
77	// 404 handler
78	app.use((_req: Request, _res: Response, next: NextFunction) => {
79	  next(new AppError(404, 'NOT_FOUND', 'Resource not found'));
80	});
81	
82	// Global error handler
83	app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
84	  const traceId = traceStore.getStore()?.traceId || 'unknown';
85	
86	  if (err instanceof AppError) {
87	    res.status(err.statusCode).json({
88	      statusCode: err.statusCode,
89	      code: err.code,
90	      message: err.message,
91	      traceId,
92	    });
93	    return;
94	  }
95	
96	  systemLogger.error('unhandled_error', {
97	    error: err.message,
98	    stack: err.stack,
99	  });
100	
101	  res.status(500).json({
102	    statusCode: 500,
103	    code: 'INTERNAL_ERROR',
104	    message: 'Internal server error',
105	    traceId,
106	  });
107	});
108	
109	export default app;
110

