1	import express, { Request, Response, NextFunction } from 'express';
2	import helmet from 'helmet';
3	import compression from 'compression';
4	import swaggerUi from 'swagger-ui-express';
5	import path from 'path';
6	import { auditMiddleware } from './middleware/audit.middleware';
7	import { AppError } from './utils/errors';
8	import { traceStore } from './utils/logger';
9	import { createCategoryLogger } from './utils/logger';
10	import authRoutes from './routes/auth.routes';
11	import accountsRoutes from './routes/accounts.routes';
12	import usersRoutes from './routes/users.routes';
13	import groupsRoutes from './routes/groups.routes';
14	import itinerariesRoutes from './routes/itineraries.routes';
15	import filesRoutes from './routes/files.routes';
16	import notificationsRoutes from './routes/notifications.routes';
17	import reportsRoutes from './routes/reports.routes';
18	import importRoutes from './routes/import.routes';
19	import faceRoutes from './routes/face.routes';
20	import qualityRoutes from './routes/quality.routes';
21	import auditRoutes from './routes/audit.routes';
22	
23	const systemLogger = createCategoryLogger('system');
24	
25	const app = express();
26	
27	// Security and compression
28	app.use(helmet());
29	app.use(compression());
30	app.use(express.json());
31	app.use(express.urlencoded({ extended: true }));
32	
33	// Trace ID on every request
34	app.use(auditMiddleware);
35	
36	// Health check
37	app.get('/health', (_req: Request, res: Response) => {
38	  res.json({ status: 'ok', timestamp: new Date().toISOString() });
39	});
40	
41	// Swagger UI
42	const stubSpec = {
43	  openapi: '3.0.3',
44	  info: {
45	    title: 'Hospitality Operations Intelligence API',
46	    version: '1.0.0',
47	    description: 'Hospitality Operations Intelligence & Group Itinerary Platform',
48	  },
49	  servers: [{ url: 'http://localhost:3000', description: 'Local' }],
50	  paths: {
51	    '/health': {
52	      get: {
53	        tags: ['Health'],
54	        summary: 'Health check',
55	        responses: {
56	          '200': {
57	            description: 'OK',
58	            content: {
59	              'application/json': {
60	                schema: {
61	                  type: 'object',
62	                  properties: {
63	                    status: { type: 'string', example: 'ok' },
64	                    timestamp: { type: 'string', format: 'date-time' },
65	                  },
66	                },
67	              },
68	            },
69	          },
70	        },
71	      },
72	    },
73	  },
74	};
75	
76	app.use('/api/docs', swaggerUi.serve, swaggerUi.setup(stubSpec));
77	
78	// API routes
79	app.use('/auth', authRoutes);
80	app.use('/accounts', accountsRoutes);
81	app.use('/users', usersRoutes);
82	app.use('/groups', groupsRoutes);
83	app.use('/groups/:groupId/itineraries', itinerariesRoutes);
84	app.use('/groups/:groupId/files', filesRoutes);
85	app.use('/notifications', notificationsRoutes);
86	app.use('/reports', reportsRoutes);
87	app.use('/import', importRoutes);
88	app.use('/face', faceRoutes);
89	app.use('/quality', qualityRoutes);
90	app.use('/audit-logs', auditRoutes);
91	
92	// Static file serving for exports
93	app.use('/exports', express.static(path.resolve('exports')));
94	
95	// 404 handler
96	app.use((_req: Request, _res: Response, next: NextFunction) => {
97	  next(new AppError(404, 'NOT_FOUND', 'Resource not found'));
98	});
99	
100	// Global error handler
101	app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
102	  const traceId = traceStore.getStore()?.traceId || 'unknown';
103	
104	  if (err instanceof AppError) {
105	    res.status(err.statusCode).json({
106	      statusCode: err.statusCode,
107	      code: err.code,
108	      message: err.message,
109	      traceId,
110	    });
111	    return;
112	  }
113	
114	  systemLogger.error('unhandled_error', {
115	    error: err.message,
116	    stack: err.stack,
117	  });
118	
119	  res.status(500).json({
120	    statusCode: 500,
121	    code: 'INTERNAL_ERROR',
122	    message: 'Internal server error',
123	    traceId,
124	  });
125	});
126	
127	export default app;
