23	
24	const systemLogger = createCategoryLogger('system');
25	
26	const app = express();
27	
28	// Security and compression
29	app.use(helmet());
30	app.use(compression());
31	app.use(express.json());
32	app.use(express.urlencoded({ extended: true }));
33	
34	// Trace ID on every request
35	app.use(auditMiddleware);
36	
