57	app.use('/audit-logs', auditRoutes);
58	
59	// Static file serving for exports
60	app.use('/exports', express.static(path.resolve('exports')));
61	
62	// 404 handler
63	app.use((_req: Request, _res: Response, next: NextFunction) => {
64	  next(new AppError(404, 'NOT_FOUND', 'Resource not found'));
65	});
66	
67	// Global error handler
68	app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
69	  const traceId = traceStore.getStore()?.traceId || 'unknown';
70	
71	  if (err instanceof AppError) {
72	    res.status(err.statusCode).json({
73	      statusCode: err.statusCode,
74	      code: err.code,
75	      message: err.message,
76	      traceId,
77	    });
78	    return;
79	  }
80	
81	  systemLogger.error('unhandled_error', {
82	    error: err.message,
83	    stack: err.stack,
84	  });
85	
86	  res.status(500).json({
87	    statusCode: 500,
88	    code: 'INTERNAL_ERROR',
89	    message: 'Internal server error',
90	    traceId,
91	  });
92	});
93	
94	export default app;
