5	interface ReportParams { propertyId?: string; from: string; to: string; groupBy?: string; roomType?: string; }
6	
7	function scopeWhere(params: ReportParams, managerPropertyId?: string): { where: string; replacements: string[] } {
8	  const clauses: string[] = [];
9	  const replacements: string[] = [];
10	  const propId = managerPropertyId || params.propertyId;
11	  if (propId) { clauses.push('r.property_id = ?'); replacements.push(propId); }
12	  clauses.push('r.check_in_date <= ?'); replacements.push(params.to);
13	  clauses.push('r.check_out_date >= ?'); replacements.push(params.from);
14	  if (params.roomType) { clauses.push('rm.room_type = ?'); replacements.push(params.roomType); }
15	  return { where: clauses.length ? 'WHERE ' + clauses.join(' AND ') : '', replacements };
16	}
17	
18	function groupByClause(groupBy: string): string {
19	  switch (groupBy) {
20	    case 'week': return "DATE_FORMAT(r.check_in_date, '%x-W%v')";
21	    case 'month': return "DATE_FORMAT(r.check_in_date, '%Y-%m')";
22	    default: return 'r.check_in_date';
23	  }
24	}
