26	export async function occupancy(params: ReportParams, managerPropertyId?: string) {
27	  const gb = groupByClause(params.groupBy || 'day');
28	  const { where, replacements } = scopeWhere(params, managerPropertyId);
29	  const sql = `SELECT ${gb} as period, COUNT(DISTINCT r.room_id) as occupied_rooms,
30	    (SELECT COUNT(*) FROM rooms rm2 WHERE rm2.status != 'maintenance'
31	     ${managerPropertyId || params.propertyId ? "AND rm2.property_id = '" + (managerPropertyId || params.propertyId) + "'" : ''}) as total_rooms
32	    FROM reservations r LEFT JOIN rooms rm ON r.room_id = rm.id
33	    ${where} AND r.status IN ('confirmed','checked_in','checked_out')
34	    GROUP BY period ORDER BY period`;
35	  return sequelize.query(sql, { replacements, type: QueryTypes.SELECT });
36	}
