38	export async function adr(params: ReportParams, managerPropertyId?: string) {
39	  const gb = groupByClause(params.groupBy || 'day');
40	  const { where, replacements } = scopeWhere(params, managerPropertyId);
41	  const sql = `SELECT ${gb} as period, SUM(r.rate_cents) as total_revenue, COUNT(*) as occupied_nights,
42	    ROUND(SUM(r.rate_cents) / NULLIF(COUNT(*), 0), 2) as adr_cents
43	    FROM reservations r LEFT JOIN rooms rm ON r.room_id = rm.id
44	    ${where} AND r.status IN ('checked_in','checked_out')
45	    GROUP BY period ORDER BY period`;
46	  return sequelize.query(sql, { replacements, type: QueryTypes.SELECT });
47	}
