55	    ROUND(SUM(r.rate_cents) / NULLIF((SELECT COUNT(*) FROM rooms rm2 WHERE rm2.status != 'maintenance'
56	     ${managerPropertyId || params.propertyId ? "AND rm2.property_id = '" + (managerPropertyId || params.propertyId) + "'" : ''}), 0), 2) as revpar_cents
57	    FROM reservations r LEFT JOIN rooms rm ON r.room_id = rm.id
