11	const STAFFING_COLUMNS = ['employee_id', 'effective_date', 'position', 'department', 'property_id', 'signed_off_by'];
12	const STAFFING_REQUIRED = ['employee_id', 'effective_date', 'position'];
13	const EVAL_COLUMNS = ['employee_id', 'effective_date', 'score', 'result', 'rewards', 'penalties', 'signed_off_by'];
14	const EVAL_REQUIRED = ['employee_id', 'effective_date'];
15	const MAX_RETRY_ATTEMPTS = 3;
16	
17	export async function getTemplate(datasetType: string): Promise<ExcelJS.Workbook> {
18	  const wb = new ExcelJS.Workbook();
19	  const ws = wb.addWorksheet(datasetType);
20	  const cols = datasetType === 'staffing' ? STAFFING_COLUMNS : EVAL_COLUMNS;
21	  ws.addRow(cols);
22	  return wb;
23	}
24	
25	function parseRows(ws: ExcelJS.Worksheet, headers: string[], datasetType: string) {
26	  const errors: { rowNumber: number; field: string | null; reason: string }[] = [];
27	  const validRows: Record<string, string>[] = [];
28	  const required = datasetType === 'staffing' ? STAFFING_REQUIRED : EVAL_REQUIRED;
29	
30	  ws.eachRow((row, rowNum) => {
31	    if (rowNum === 1) return;
32	    const data: Record<string, string> = {};
33	    headers.forEach((h, i) => { data[h] = row.getCell(i + 1).text?.trim() || ''; });
34	
35	    let hasError = false;
36	    for (const req of required) {
37	      if (!data[req]) { errors.push({ rowNumber: rowNum, field: req, reason: `${req} is required` }); hasError = true; }
38	    }
39	    if (data.effective_date && !/^\d{4}-\d{2}-\d{2}$/.test(data.effective_date)) {
40	      errors.push({ rowNumber: rowNum, field: 'effective_date', reason: 'Must be YYYY-MM-DD' }); hasError = true;
41	    }
42	    if (datasetType === 'evaluation' && data.score && isNaN(Number(data.score))) {
43	      errors.push({ rowNumber: rowNum, field: 'score', reason: 'Must be a number' }); hasError = true;
44	    }
45	
46	    if (!hasError) validRows.push(data);
47	  });
48	
49	  return { errors, validRows, totalRows: (validRows.length + errors.length) };
50	}
51	
52	export async function uploadAndValidate(userId: string, datasetType: string, buffer: Buffer) {
53	  const batchId = uuidv4();
54	  const traceId = traceStore.getStore()?.traceId || null;
55	
56	  await ImportBatch.create({ id: batchId, user_id: userId, batch_type: datasetType, status: 'pending', trace_id: traceId, created_at: new Date() });
57	
58	  const wb = new ExcelJS.Workbook();
59	  await wb.xlsx.load(buffer as unknown as ExcelJS.Buffer);
60	  const ws = wb.worksheets[0];
61	  if (!ws) throw new AppError(400, 'VALIDATION_ERROR', 'No worksheet found');
62	
63	  const headers = (ws.getRow(1).values as string[]).slice(1).map(h => String(h).trim().toLowerCase());
64	  const required = datasetType === 'staffing' ? STAFFING_REQUIRED : EVAL_REQUIRED;
65	  const missing = required.filter(r => !headers.includes(r));
66	  if (missing.length > 0) throw new AppError(400, 'VALIDATION_ERROR', `Missing required columns: ${missing.join(', ')}`);
67	
68	  const { errors, validRows, totalRows } = parseRows(ws, headers, datasetType);
69	
70	  for (const err of errors) {
71	    await ImportError.create({ id: uuidv4(), batch_id: batchId, row_number: err.rowNumber, field: err.field, reason: err.reason });
72	  }
73	
74	  await ImportBatch.update({ total_rows: totalRows, error_rows: errors.length, success_rows: validRows.length, status: 'pending' }, { where: { id: batchId } });
75	
76	  return { batchId, totalRows, validRows: validRows.length, errorRows: errors.length, errors };
77	}
