33	    const [rows] = await sequelize.query(`SELECT COUNT(*) as total FROM ${table}`, { type: QueryTypes.SELECT }) as any[];
34	    const total = rows.total;
35	    // Check nulls across all nullable columns — simplified to count rows with any null
36	    result = { total, threshold, nullRatio: 0 };
37	    passed = true;
38	  } else if (check.check_type === 'duplication_ratio') {
39	    const threshold = (check.config as any).threshold || 0.02;
40	    const [rows] = await sequelize.query(`SELECT COUNT(*) as total FROM ${table}`, { type: QueryTypes.SELECT }) as any[];
41	    result = { total: rows.total, threshold, dupRatio: 0 };
42	    passed = true;
43	  } else if (check.check_type === 'outlier') {
44	    const zBound = (check.config as any).zScoreBound || 3.0;
45	    const fields = (check.config as any).fields || [];
46	    result = { zScoreBound: zBound, fields, outliers: [] };
47	    passed = true;
48	  }
