52	export async function completeSession(sessionId: string, userId: string) {
53	  const session = await FaceEnrollmentSession.findOne({ where: { id: sessionId, user_id: userId } });
54	  if (!session || session.status !== 'in_progress') throw new AppError(400, 'VALIDATION_ERROR', 'Invalid or expired session');
55	
56	  const angles = session.angles_captured as Record<string, { captured: boolean; passed: boolean }>;
57	  for (const angle of REQUIRED_ANGLES) {
58	    if (!angles[angle]?.captured) throw new AppError(400, 'VALIDATION_ERROR', `Missing capture for angle: ${angle}`);
59	    if (!angles[angle]?.passed) throw new AppError(400, 'VALIDATION_ERROR', `Liveness failed for angle: ${angle}`);
60	  }
61	
62	  // Deactivate previous enrollments
63	  await FaceEnrollment.update({ status: 'deactivated' }, { where: { user_id: userId, status: 'active' } });
64	
65	  // Get next version
66	  const maxVersion = await FaceEnrollment.max('version', { where: { user_id: userId } }) as number || 0;
67	
68	  // Encrypt template
69	  const template = JSON.stringify({ angles: session.angles_captured, enrolledAt: new Date().toISOString() });
70	  const encryptedTemplate = encrypt(template);
71	  const templatePath = path.join('face-templates', `${uuidv4()}.enc`);
72	  fs.writeFileSync(path.resolve(templatePath), encryptedTemplate);
73	
74	  const enrollment = await FaceEnrollment.create({
