76	    template_path: templatePath, angles_captured: session.angles_captured,
77	    liveness_passed: true, liveness_meta: session.angles_captured,
78	    raw_image_expires_at: new Date(Date.now() + 24 * 60 * 60 * 1000),
79	  });
80	
81	  await FaceEnrollmentSession.update({ status: 'completed' }, { where: { id: sessionId } });
82	  return { enrollmentId: enrollment.id, version: enrollment.version };
