1	import cron from 'node-cron';
2	import fs from 'fs';
3	import path from 'path';
4	import { Op } from 'sequelize';
5	import { FaceEnrollment, FaceEnrollmentSession } from '../models/face.model';
6	import { QualityCheck } from '../models/quality.model';
7	import { createCategoryLogger } from '../utils/logger';
8	import { runCheck } from '../services/quality.service';
9	
10	const logger = createCategoryLogger('system');
11	
12	// Hard-delete raw face images past 24h retention
13	async function cleanupFaceImages(): Promise<void> {
14	  try {
15	    const expired = await FaceEnrollment.findAll({
16	      where: {
17	        raw_image_path: { [Op.ne]: null },
18	        raw_image_expires_at: { [Op.lt]: new Date() },
19	      },
20	    });
21	
22	    for (const enrollment of expired) {
23	      if (enrollment.raw_image_path) {
24	        try { fs.unlinkSync(path.resolve(enrollment.raw_image_path)); } catch { /* already gone */ }
25	      }
26	      await FaceEnrollment.update(
27	        { raw_image_path: null, raw_image_expires_at: null },
28	        { where: { id: enrollment.id } }
29	      );
30	    }
31	
32	    // Expire stale sessions (30 min)
33	    await FaceEnrollmentSession.update(
34	      { status: 'expired' },
35	      { where: { status: 'in_progress', expires_at: { [Op.lt]: new Date() } } }
36	    );
37	
38	    if (expired.length > 0) {
39	      logger.info('Face image cleanup completed', { deletedCount: expired.length });
40	    }
41	  } catch (err) {
42	    logger.error('Face image cleanup failed', { error: err instanceof Error ? err.message : String(err) });
43	  }
44	}
45	
46	// Delete generated export archives past 24h
47	async function cleanupExports(): Promise<void> {
48	  try {
49	    const exportsDir = path.resolve('exports');
50	    if (!fs.existsSync(exportsDir)) return;
51	
52	    const files = fs.readdirSync(exportsDir);
53	    const cutoff = Date.now() - 24 * 60 * 60 * 1000;
54	    let deletedCount = 0;
55	
56	    for (const file of files) {
57	      if (file === '.gitkeep') continue;
58	      const filePath = path.join(exportsDir, file);
59	      const stat = fs.statSync(filePath);
60	      if (stat.mtimeMs < cutoff) {
61	        fs.unlinkSync(filePath);
62	        deletedCount++;
63	      }
64	    }
65	
66	    if (deletedCount > 0) {
67	      logger.info('Export cleanup completed', { deletedCount });
68	    }
69	  } catch (err) {
70	    logger.error('Export cleanup failed', { error: err instanceof Error ? err.message : String(err) });
71	  }
72	}
73	
74	// Run all configured quality checks
75	async function runScheduledQualityChecks(): Promise<void> {
76	  try {
77	    const checks = await QualityCheck.findAll();
78	    for (const check of checks) {
79	      try {
80	        await runCheck(check.id);
81	      } catch (err) {
82	        logger.error('Scheduled quality check failed', { checkId: check.id, error: err instanceof Error ? err.message : String(err) });
83	      }
84	    }
85	    if (checks.length > 0) {
86	      logger.info('Scheduled quality checks completed', { count: checks.length });
87	    }
88	  } catch (err) {
89	    logger.error('Quality check scheduler failed', { error: err instanceof Error ? err.message : String(err) });
90	  }
91	}
92	
93	export function registerCleanupJobs(): void {
94	  // Face image cleanup — every 15 minutes
95	  cron.schedule('*/15 * * * *', cleanupFaceImages);
96	
97	  // Export archive cleanup — every hour
98	  cron.schedule('0 * * * *', cleanupExports);
99	
100	  // Scheduled quality checks — every hour
101	  cron.schedule('30 * * * *', runScheduledQualityChecks);
102	
103	  logger.info('Background jobs registered', {
104	    jobs: ['face-image-cleanup (every 15m)', 'export-cleanup (every 1h)', 'quality-checks (every 1h)'],
105	  });
106	}
