9	export async function queryNotifications(req: AuthenticatedRequest, res: Response, next: NextFunction): Promise<void> {
10	  try {
11	    const groupId = req.query.groupId as string;
12	    if (!groupId) throw new AppError(400, 'VALIDATION_ERROR', 'groupId is required');
13	
14	    const member = await GroupMember.findOne({ where: { group_id: groupId, user_id: req.user!.id } });
15	    if (!member) throw new AppError(403, 'FORBIDDEN', 'Not a member of this group');
16	
17	    const limit = Math.min(100, Math.max(1, parseInt(req.query.limit as string) || 50));
18	    const afterCursor = req.query.after as string | undefined;
19	
20	    const whereClause: any = { group_id: groupId };
21	
22	    if (afterCursor) {
23	      // Support after=<notificationId> (UUID) — look up that notification's created_at for stable ordering
24	      const anchor = await Notification.findByPk(afterCursor);
25	      if (anchor) {
26	        whereClause[Op.or] = [
27	          { created_at: { [Op.gt]: anchor.created_at } },
28	          { created_at: anchor.created_at, id: { [Op.gt]: anchor.id } },
29	        ];
30	      } else {
31	        // Fallback: try base64 JSON cursor for backwards compat
32	        try {
33	          const decoded = JSON.parse(Buffer.from(afterCursor, 'base64').toString('utf8'));
34	          whereClause[Op.or] = [
35	            { created_at: { [Op.gt]: decoded.createdAt } },
36	            { created_at: decoded.createdAt, id: { [Op.gt]: decoded.id } },
37	          ];
38	        } catch {
39	          throw new AppError(400, 'VALIDATION_ERROR', 'Invalid cursor');
40	        }
41	      }
42	    }
43	
44	    const notifications = await Notification.findAll({
45	      where: whereClause,
46	      order: [['created_at', 'ASC'], ['id', 'ASC']],
47	      limit,
48	    });
49	
50	    let nextCursor: string | null = null;
51	    if (notifications.length === limit) {
52	      // Return the last notification ID as the cursor
53	      nextCursor = notifications[notifications.length - 1].id;
54	    }
55	
56	    res.json({ data: notifications, nextCursor });
57	  } catch (e) { next(e); }
58	}
