13	function getManagerScope(req: AuthenticatedRequest): string | undefined {
14	  if (req.user!.role === 'manager') {
15	    if (!req.user!.propertyId) throw new AppError(403, 'FORBIDDEN', 'Manager must be assigned to a property');
16	    if (req.query.propertyId && req.query.propertyId !== req.user!.propertyId)
17	      throw new AppError(403, 'FORBIDDEN', 'Access denied to this property');
18	    return req.user!.propertyId;
19	  }
20	  return undefined;
21	}
