51	export async function exportReport(req: AuthenticatedRequest, res: Response, next: NextFunction): Promise<void> {
52	  try {
53	    const scope = getManagerScope(req);
54	    const { reportType, from, to, format, groupBy, propertyId, includePii } = req.body;
55	
56	    if (includePii) {
57	      const { User } = require('../models/user.model');
58	      const user = await User.findByPk(req.user!.id);
59	      if (!user?.pii_export_allowed) throw new AppError(403, 'FORBIDDEN', 'PII export not permitted');
60	    }
61	
62	    let data: unknown[];
63	    switch (reportType) {
64	      case 'occupancy': data = await reportingService.occupancy({ propertyId, from, to, groupBy }, scope); break;
65	      case 'adr': data = await reportingService.adr({ propertyId, from, to, groupBy }, scope); break;
66	      case 'revpar': data = await reportingService.revpar({ propertyId, from, to, groupBy }, scope); break;
67	      case 'revenue_mix': data = await reportingService.revenueMix({ propertyId, from, to, groupBy }, scope); break;
68	      default: throw new AppError(400, 'VALIDATION_ERROR', 'Invalid reportType');
69	    }
