36	/**
37	 * Check idempotency for an update operation.
38	 * Returns stored response if key exists with same hash, or null to proceed.
39	 * Throws 409 if key exists with different hash.
40	 */
41	export async function checkIdempotency(
42	  key: string, actorId: string, operation: string, body: unknown
43	): Promise<unknown | null> {
44	  const existing = await IdempotencyKey.findOne({ where: { key, actor_id: actorId } });
45	  if (!existing) return null; // proceed
46	
47	  if (new Date(existing.expires_at) < new Date()) {
48	    // Expired — delete and proceed
49	    await IdempotencyKey.destroy({ where: { id: existing.id } });
50	    return null;
51	  }
52	
53	  const reqHash = hashBody(body);
54	  if (existing.request_hash === reqHash) {
55	    // Same request — return stored response (replay)
56	    return existing.response_snapshot;
57	  }
58	
59	  // Different body with same key — conflict
60	  throw Object.assign(new Error('Idempotency key reused with different request body'), {
61	    statusCode: 409, code: 'IDEMPOTENCY_CONFLICT',
62	    message: 'Idempotency key already used with a different request',
63	  });
64	}
